// // This module selects between two 32-bit inputs, inputA and inputB, based on the value of the control signal; when control is 1, the output is set to inputA, and when control is 0, the output is set to inputB.
module top_module(inputA, inputB, control, out);parameter bits = 32;
    input [bits-1:0] inputA;
    input [bits-1:0] inputB;
    input control; 
    output [bits-1:0] out; 
    assign out= (control==1'b0) ?inputA:inputB;
endmodule
